const BASE_URL = '/api/products';

export const getProducts = () => fetch(BASE_URL).then(r => r.json());

export const createProduct = (data) => 
  fetch(BASE_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data)
  }).then(r => r.json());

export const updateProduct = (id, data) => 
  fetch(`${BASE_URL}/${id}`, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data)
  }).then(r => r.json());

export const deleteProduct = async (id) => {
  const response = await fetch(`/api/products/${id}`, {
    method: 'DELETE',
  });

  console.log(`DELETE /api/products/${id} → статус: ${response.status}`);

  // 204 — это нормальный успешный ответ для DELETE
  if (response.status === 204) {
    return true; // успех
  }

  // Если не 204 — читаем ошибку
  if (!response.ok) {
    let errorText = '';
    try {
      errorText = await response.text();
    } catch {}
    throw new Error(`Удаление не удалось: ${response.status} — ${errorText}`);
  }

  return true;
};
